func (r *Resolver) projectRoot(projectID string) string {
	if r.State != nil {
		if proj, ok := r.State.GetProjectSnapshotByID(projectID); ok && proj.Path != "" {
			return proj.Path
		}
	}
	return r.WorkingDir
}

